// UniLLM Cache-Aware Attention Kernel Template
// This kernel directly integrates with our hybrid cache system
// providing the key competitive advantage over vLLM and SGLang

#include <cuda_runtime.h>
#include <cuda_fp16.h>
{{#if has_tensor_cores}}
#include <mma.h>
using namespace nvcuda;
{{/if}}

// Template parameters
#define HEAD_DIM {{parameters.head_dim}}
#define NUM_HEADS {{parameters.num_heads}}
#define BLOCK_SIZE {{block_size}}
#define CACHE_LINE_SIZE {{cache_line_size}}
#define WARP_SIZE {{warp_size}}

{{optimize_for_tensor_cores has_tensor_cores}}

// Cache integration structures
struct CacheHandle {
    void* l1_radix_ptr;
    void* l2_paged_ptr;
    void* l3_compressed_ptr;
    uint32_t cache_level;
    uint32_t cache_offset;
    float hit_probability;
};

struct UniLLMCacheMetadata {
    CacheHandle* cache_handles;
    uint32_t* sequence_ids;
    uint32_t* token_offsets;
    float* cache_scores;
    uint32_t num_sequences;
};

// Hardware-optimized memory access patterns
{{#if (gpu_arch_check gpu_architecture "Ada")}}
// Ada Lovelace optimizations
#define SHARED_MEM_SIZE 49152  // 48KB shared memory
#define TENSOR_CORE_SHAPE_M 16
#define TENSOR_CORE_SHAPE_N 8
#define TENSOR_CORE_SHAPE_K 16
{{else if (gpu_arch_check gpu_architecture "Ampere")}}
// Ampere optimizations
#define SHARED_MEM_SIZE 49152  // 48KB shared memory
#define TENSOR_CORE_SHAPE_M 16
#define TENSOR_CORE_SHAPE_N 8
#define TENSOR_CORE_SHAPE_K 16
{{else}}
// Default optimizations
#define SHARED_MEM_SIZE 32768  // 32KB shared memory
#define TENSOR_CORE_SHAPE_M 16
#define TENSOR_CORE_SHAPE_N 8
#define TENSOR_CORE_SHAPE_K 8
{{/if}}

// Memory coalescing optimization
#define COALESCING_FACTOR {{memory_coalescing_factor}}

__global__ void cache_aware_attention_kernel(
    // Input tensors
    const half* __restrict__ query,     // [batch, seq_len, num_heads, head_dim]
    const half* __restrict__ key,       // [batch, kv_len, num_heads, head_dim]
    const half* __restrict__ value,     // [batch, kv_len, num_heads, head_dim]

    // Cache integration (UniLLM innovation)
    const UniLLMCacheMetadata* __restrict__ cache_metadata,

    // Output
    half* __restrict__ output,          // [batch, seq_len, num_heads, head_dim]

    // Dimensions
    const int batch_size,
    const int seq_len,
    const int kv_len,
    const float scale
) {
    // Thread and block indices
    const int batch_idx = blockIdx.x;
    const int head_idx = blockIdx.y;
    const int seq_idx = blockIdx.z * BLOCK_SIZE + threadIdx.x;
    const int warp_id = threadIdx.x / WARP_SIZE;
    const int lane_id = threadIdx.x % WARP_SIZE;

    // Bounds checking
    if (batch_idx >= batch_size || head_idx >= NUM_HEADS || seq_idx >= seq_len) {
        return;
    }

    // Shared memory allocation for cache-aware optimization
    __shared__ half s_query[BLOCK_SIZE * HEAD_DIM];
    __shared__ half s_key[BLOCK_SIZE * HEAD_DIM];
    __shared__ half s_value[BLOCK_SIZE * HEAD_DIM];
    __shared__ float s_cache_scores[BLOCK_SIZE];
    __shared__ CacheHandle s_cache_handles[BLOCK_SIZE];

    // Load cache metadata for this sequence
    const uint32_t sequence_id = cache_metadata->sequence_ids[batch_idx];
    const CacheHandle cache_handle = cache_metadata->cache_handles[batch_idx];

    // Cache-aware data loading (UniLLM innovation)
    // Priority 1: L1 Radix Cache (highest hit probability)
    if (cache_handle.cache_level == 1 && cache_handle.hit_probability > 0.8) {
        // Direct load from L1 radix cache
        const half* l1_cache_ptr = (const half*)cache_handle.l1_radix_ptr;

        // Vectorized load from L1 cache with memory coalescing
        #pragma unroll
        for (int i = 0; i < HEAD_DIM; i += COALESCING_FACTOR / sizeof(half)) {
            float4 cache_data = reinterpret_cast<const float4*>(
                &l1_cache_ptr[cache_handle.cache_offset + i]
            )[0];
            reinterpret_cast<float4*>(&s_key[threadIdx.x * HEAD_DIM + i])[0] = cache_data;
        }
    }
    // Priority 2: L2 Paged Cache
    else if (cache_handle.cache_level == 2 && cache_handle.hit_probability > 0.5) {
        // Load from L2 paged cache with block-level efficiency
        const half* l2_cache_ptr = (const half*)cache_handle.l2_paged_ptr;

        // Coalesced memory access pattern
        const int global_offset = batch_idx * kv_len * NUM_HEADS * HEAD_DIM +
                                 head_idx * kv_len * HEAD_DIM +
                                 cache_handle.cache_offset;

        #pragma unroll
        for (int i = threadIdx.x; i < HEAD_DIM; i += BLOCK_SIZE) {
            s_key[threadIdx.x * HEAD_DIM + i] = l2_cache_ptr[global_offset + i];
        }
    }
    // Fallback: Direct memory access
    else {
        // Standard memory access pattern with optimization
        const int global_offset = batch_idx * kv_len * NUM_HEADS * HEAD_DIM +
                                 head_idx * kv_len * HEAD_DIM;

        // Vectorized load with memory coalescing
        #pragma unroll
        for (int i = 0; i < HEAD_DIM; i += 4) {
            float4 key_data = reinterpret_cast<const float4*>(
                &key[global_offset + seq_idx * HEAD_DIM + i]
            )[0];
            reinterpret_cast<float4*>(&s_key[threadIdx.x * HEAD_DIM + i])[0] = key_data;
        }
    }

    // Load query (always from global memory)
    const int query_offset = batch_idx * seq_len * NUM_HEADS * HEAD_DIM +
                            seq_idx * NUM_HEADS * HEAD_DIM +
                            head_idx * HEAD_DIM;

    #pragma unroll
    for (int i = 0; i < HEAD_DIM; i += 4) {
        float4 query_data = reinterpret_cast<const float4*>(&query[query_offset + i])[0];
        reinterpret_cast<float4*>(&s_query[threadIdx.x * HEAD_DIM + i])[0] = query_data;
    }

    __syncthreads();

    // Attention computation with Tensor Core optimization
{{#if has_tensor_cores}}
    // Use Tensor Cores for matrix multiplication (NVIDIA advantage)
    wmma::fragment<wmma::matrix_a, TENSOR_CORE_SHAPE_M, TENSOR_CORE_SHAPE_N, TENSOR_CORE_SHAPE_K, half, wmma::row_major> a_frag;
    wmma::fragment<wmma::matrix_b, TENSOR_CORE_SHAPE_M, TENSOR_CORE_SHAPE_N, TENSOR_CORE_SHAPE_K, half, wmma::col_major> b_frag;
    wmma::fragment<wmma::accumulator, TENSOR_CORE_SHAPE_M, TENSOR_CORE_SHAPE_N, TENSOR_CORE_SHAPE_K, float> acc_frag;

    wmma::fill_fragment(acc_frag, 0.0f);

    // Perform attention computation using Tensor Cores
    for (int k = 0; k < HEAD_DIM; k += TENSOR_CORE_SHAPE_K) {
        wmma::load_matrix_sync(a_frag, &s_query[threadIdx.x * HEAD_DIM + k], HEAD_DIM);
        wmma::load_matrix_sync(b_frag, &s_key[threadIdx.x * HEAD_DIM + k], HEAD_DIM);
        wmma::mma_sync(acc_frag, a_frag, b_frag, acc_frag);
    }

    // Store results
    wmma::store_matrix_sync(&s_cache_scores[threadIdx.x], acc_frag, BLOCK_SIZE, wmma::mem_row_major);
{{else}}
    // Standard FP16 computation for non-Tensor Core GPUs
    float attention_score = 0.0f;

    #pragma unroll
    for (int i = 0; i < HEAD_DIM; ++i) {
        attention_score += __half2float(s_query[threadIdx.x * HEAD_DIM + i]) *
                          __half2float(s_key[threadIdx.x * HEAD_DIM + i]);
    }

    s_cache_scores[threadIdx.x] = attention_score * scale;
{{/if}}

    __syncthreads();

    // Softmax computation with warp-level optimization
    float max_score = s_cache_scores[threadIdx.x];

    // Warp-level reduction for maximum
    #pragma unroll
    for (int offset = WARP_SIZE / 2; offset > 0; offset /= 2) {
        max_score = fmaxf(max_score, __shfl_down_sync(0xFFFFFFFF, max_score, offset));
    }

    // Broadcast maximum across warp
    max_score = __shfl_sync(0xFFFFFFFF, max_score, 0);

    // Compute exponentials
    float exp_score = expf(s_cache_scores[threadIdx.x] - max_score);
    s_cache_scores[threadIdx.x] = exp_score;

    __syncthreads();

    // Warp-level reduction for sum
    float sum_exp = exp_score;
    #pragma unroll
    for (int offset = WARP_SIZE / 2; offset > 0; offset /= 2) {
        sum_exp += __shfl_down_sync(0xFFFFFFFF, sum_exp, offset);
    }

    sum_exp = __shfl_sync(0xFFFFFFFF, sum_exp, 0);

    // Normalize
    const float attention_weight = exp_score / sum_exp;

    // Value computation with cache awareness
    half result[HEAD_DIM];

    // Cache-aware value loading (similar to key loading)
    if (cache_handle.cache_level == 1 && cache_handle.hit_probability > 0.8) {
        const half* l1_value_ptr = (const half*)cache_handle.l1_radix_ptr;

        #pragma unroll
        for (int i = 0; i < HEAD_DIM; ++i) {
            result[i] = __float2half(__half2float(l1_value_ptr[cache_handle.cache_offset + i]) * attention_weight);
        }
    } else {
        // Standard value computation
        const int value_offset = batch_idx * kv_len * NUM_HEADS * HEAD_DIM +
                                head_idx * kv_len * HEAD_DIM +
                                seq_idx * HEAD_DIM;

        #pragma unroll
        for (int i = 0; i < HEAD_DIM; ++i) {
            result[i] = __float2half(__half2float(value[value_offset + i]) * attention_weight);
        }
    }

    // Write output with vectorized stores
    const int output_offset = batch_idx * seq_len * NUM_HEADS * HEAD_DIM +
                             seq_idx * NUM_HEADS * HEAD_DIM +
                             head_idx * HEAD_DIM;

    #pragma unroll
    for (int i = 0; i < HEAD_DIM; i += 4) {
        reinterpret_cast<float4*>(&output[output_offset + i])[0] = 
            reinterpret_cast<const float4*>(&result[i])[0];
    }

    // Update cache statistics for adaptive optimization
    if (threadIdx.x == 0) {
        // Atomic update of cache hit statistics
        atomicAdd(&cache_metadata->cache_scores[batch_idx], attention_weight);
    }
}
